    {
      "term": "Transposition",
      "simpleDefinition": "Rearranging a formula to solve for a different unknown value by moving terms across the equals sign.",
      "anchor": "Change the side, change the operation (e.g., multiplication becomes division).",
      "misconception": "Thinking you can move a term without reversing its mathematical operation."
    },
    {
      "term": "Indices",
      "simpleDefinition": "Small numbers (powers) that tell you how many times to multiply a base number by itself.",
      "anchor": "The power of the number, such as squaring a value in Pythagoras' theorem.",
      "misconception": "Multiplying the base number by the index value instead of multiplying the base by itself."
    },
    {
      "term": "SOH CAH TOA",
      "simpleDefinition": "A mnemonic used to remember the three trigonometric ratios: Sine, Cosine, and Tangent.",
      "anchor": "The relationship between the angle and the sides (Opposite, Adjacent, Hypotenuse) of a right-angled triangle.",
      "misconception": "Using the wrong ratio because the sides were incorrectly labeled relative to the reference angle."
    },
    {
      "term": "Pythagoras' Theorem",
      "simpleDefinition": "A formula used to find the length of a missing side in a right-angled triangle when two sides are known.",
      "anchor": "The square of the hypotenuse is equal to the sum of the squares of the other two sides.",
      "misconception": "Forgetting to calculate the square root of the final sum to find the actual side length."
    },
    {
      "term": "Mean (Average)",
      "simpleDefinition": "The central value of a set of numbers, found by adding them all up and dividing by how many numbers there are.",
      "anchor": "Total sum divided by the count of readings.",
      "misconception": "Confusing the mean with other statistical measures like the median or mode."
    },
    {
      "term": "Percentages",
      "simpleDefinition": "A way of expressing a value as a fraction of 100, often used for tolerance or efficiency ratings.",
      "anchor": "Parts per hundred.",
      "misconception": "Calculating a percentage but failing to apply it back to the original value (e.g., adding a 10% increase)."
    }
  ],
  "anchorPhrases": [
    "Change the side, change the sign.",
    "Square it, sum it, root it.",
    "Total divided by the count.",
    "Opposite, Adjacent, and Hypotenuse."
  ],
  "misconceptionTargets": [
    "Moving a term across the equals sign without reversing the operation.",
    "Multiplying the base number by the index instead of by itself.",
    "Confusing the opposite and adjacent sides based on the angle's position.",
    "Forgetting to square root at the end of a Pythagoras calculation."
  ]
}

